                          <div style="padding:4px 0">${ev.estimates.filter(e=>e.accepted).map(e => `<div style="display:flex;justify-content:space-between;gap:12px;padding:2px 0"><span>${escHtml(e.name)}</span><span>${aud(e.amount)}</span></div>`).join('')}</div>
